import React, { useState, useCallback, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import PlantGrid from './components/PlantGrid';
import CareGuide from './components/CareGuide';
import ShippingInfo from './components/ShippingInfo';
import Newsletter from './components/Newsletter';
import Footer from './components/Footer';
import FloatingSocial from './components/FloatingSocial';
import AICareAssistant from './components/AICareAssistant';
import { Plant, CartItem } from './types';
import { PLANTS } from './constants';
import { X, Minus, Plus, Trash2, ShoppingBag } from 'lucide-react';

const App: React.FC = () => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [selectedPlant, setSelectedPlant] = useState<Plant | null>(null);

  const addToCart = useCallback((plantId: string, quantity: number = 1) => {
    const plant = PLANTS.find(p => p.id === plantId);
    if (!plant) return;

    setCart(prev => {
      const existing = prev.find(item => item.id === plantId);
      if (existing) {
        return prev.map(item => 
          item.id === plantId ? { ...item, quantity: item.quantity + quantity } : item
        );
      }
      return [...prev, { ...plant, quantity }];
    });
    setIsCartOpen(true);
  }, []);

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const cartTotal = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const cartCount = cart.reduce((acc, item) => acc + item.quantity, 0);

  return (
    <div className="min-h-screen bg-white">
      {/* SEo Hidden Header */}
      <h1 className="sr-only">Buy Room Plants Online | Room Plant - Premium Indoor Greens</h1>

      <Navbar cartCount={cartCount} onCartClick={() => setIsCartOpen(true)} />

      <main>
        <Hero onAddToCart={addToCart} />
        <ShippingInfo />
        <PlantGrid onAddToCart={(id) => addToCart(id, 1)} onViewDetails={setSelectedPlant} />
        <CareGuide />

        {/* Testimonials Placeholder */}
        <section className="py-24 bg-white overflow-hidden">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
             <div className="text-center mb-16">
              <h2 className="text-4xl font-bold text-dark mb-4">What Our Plant Parents Say</h2>
              <div className="flex justify-center space-x-1 text-cta mb-2">
                {[1, 2, 3, 4, 5].map(i => <Plus key={i} size={16} fill="currentColor" />)}
              </div>
              <p className="text-gray-500">Trusted by over 10,000+ happy customers worldwide.</p>
            </div>
            <div className="grid md:grid-cols-3 gap-8">
              {[
                { name: 'Sarah J.', city: 'New York', text: 'Stunning plants! Arrived so fresh.' },
                { name: 'Michael K.', city: 'Berlin', text: 'Fast international shipping. Recommended!' },
                { name: 'Eliza R.', city: 'Tokyo', text: 'The care guides are so helpful for beginners.' }
              ].map((t, idx) => (
                <div key={idx} className="p-8 bg-gray-50 rounded-2xl relative">
                  <span className="text-6xl text-primary/10 absolute top-4 left-4 font-serif">"</span>
                  <p className="text-gray-600 italic mb-6 relative z-10">{t.text}</p>
                  <div className="flex items-center space-x-3">
                    <div className="w-10 h-10 bg-accent/20 rounded-full flex items-center justify-center font-bold text-accent">
                      {t.name[0]}
                    </div>
                    <div>
                      <h4 className="font-bold text-dark text-sm">{t.name}</h4>
                      <p className="text-gray-400 text-xs">{t.city}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </section>

        <Newsletter />
      </main>

      <Footer />
      <FloatingSocial />
      <AICareAssistant />

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[100] overflow-hidden">
          <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="absolute inset-y-0 right-0 max-w-full flex">
            <div className="w-screen max-w-md bg-white shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
              <div className="p-6 border-b border-gray-100 flex justify-between items-center">
                <div className="flex items-center space-x-2">
                  <ShoppingBag className="text-primary" />
                  <h2 className="text-xl font-bold text-dark">Your Cart ({cartCount})</h2>
                </div>
                <button onClick={() => setIsCartOpen(false)} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                  <X size={24} />
                </button>
              </div>

              <div className="flex-grow overflow-y-auto p-6 space-y-6">
                {cart.length === 0 ? (
                  <div className="text-center py-20">
                    <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4">
                      <ShoppingBag size={40} className="text-gray-300" />
                    </div>
                    <p className="text-gray-500">Your cart is feeling empty.</p>
                    <button 
                      onClick={() => setIsCartOpen(false)}
                      className="mt-4 text-primary font-bold hover:underline"
                    >
                      Browse our collection
                    </button>
                  </div>
                ) : (
                  cart.map(item => (
                    <div key={item.id} className="flex space-x-4">
                      <div className="w-20 h-24 flex-shrink-0 bg-gray-100 rounded-lg overflow-hidden">
                        <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                      </div>
                      <div className="flex-grow">
                        <div className="flex justify-between">
                          <h4 className="font-bold text-dark">{item.name}</h4>
                          <button onClick={() => removeFromCart(item.id)} className="text-gray-300 hover:text-red-500 transition-colors">
                            <Trash2 size={18} />
