                        </div>
                        <p className="text-sm text-gray-500 mb-2">${item.price.toFixed(2)}</p>
                        <div className="flex items-center space-x-3">
                          <button 
                            onClick={() => updateQuantity(item.id, -1)}
                            className="w-8 h-8 rounded-full border border-gray-200 flex items-center justify-center hover:bg-gray-50 transition-colors"
                          >
                            <Minus size={14} />
                          </button>
                          <span className="font-medium">{item.quantity}</span>
                          <button 
                            onClick={() => updateQuantity(item.id, 1)}
                            className="w-8 h-8 rounded-full border border-gray-200 flex items-center justify-center hover:bg-gray-50 transition-colors"
                          >
                            <Plus size={14} />
                          </button>
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>

              {cart.length > 0 && (
                <div className="p-6 border-t border-gray-100 space-y-4">
                  <div className="flex justify-between text-lg">
                    <span className="text-gray-600">Subtotal</span>
                    <span className="font-bold text-dark">${cartTotal.toFixed(2)}</span>
                  </div>
                  <p className="text-xs text-gray-400">Shipping and taxes calculated at checkout.</p>
                  <button className="w-full py-4 bg-primary text-white rounded-xl font-bold text-lg hover:bg-primary/90 transition-all shadow-lg shadow-primary/20">
                    Proceed to Checkout
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Plant Details Modal */}
      {selectedPlant && (
        <div className="fixed inset-0 z-[110] overflow-hidden flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-md" onClick={() => setSelectedPlant(null)}></div>
          <div className="relative bg-white w-full max-w-4xl max-h-[90vh] rounded-3xl overflow-hidden shadow-2xl flex flex-col md:flex-row animate-in zoom-in-95 duration-200">
            <button 
              onClick={() => setSelectedPlant(null)}
              className="absolute top-4 right-4 z-10 p-2 bg-white/80 backdrop-blur rounded-full text-dark hover:bg-white transition-colors shadow-lg"
            >
              <X size={20} />
            </button>

            <div className="md:w-1/2 h-64 md:h-auto overflow-hidden">
              <img src={selectedPlant.image} alt={selectedPlant.name} className="w-full h-full object-cover" />
            </div>

            <div className="md:w-1/2 p-8 md:p-12 overflow-y-auto">
              <div className="flex items-center space-x-2 text-primary text-sm font-bold uppercase tracking-wider mb-2">
                <ShoppingBag size={16} />
                <span>Shop Premium</span>
              </div>
              <h2 className="text-3xl font-serif font-bold text-dark mb-1">{selectedPlant.name}</h2>
              <p className="text-gray-500 italic mb-6">{selectedPlant.scientificName}</p>

              <div className="flex items-center space-x-4 mb-8">
                <span className="text-3xl font-bold text-primary">${selectedPlant.price.toFixed(2)}</span>
                <div className="flex items-center space-x-1 text-cta">
                  <Star size={18} fill="currentColor" />
                  <span className="font-bold">{selectedPlant.rating}</span>
                  <span className="text-gray-400 text-sm font-normal">({selectedPlant.reviewsCount} reviews)</span>
                </div>
              </div>

              <div className="space-y-6 mb-10">
                <div>
                  <h4 className="font-bold text-dark mb-2">Description</h4>
                  <p className="text-gray-600 leading-relaxed">{selectedPlant.description}</p>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="p-3 bg-gray-50 rounded-xl">
                    <p className="text-xs text-gray-400 uppercase font-bold mb-1">Care Level</p>
                    <p className="font-bold text-dark">{selectedPlant.careLevel}</p>
                  </div>
                  <div className="p-3 bg-gray-50 rounded-xl">
                    <p className="text-xs text-gray-400 uppercase font-bold mb-1">Category</p>
                    <p className="font-bold text-dark capitalize">{selectedPlant.category}</p>
                  </div>
                </div>
              </div>

              <div className="flex space-x-4">
                <button 
                  onClick={() => { addToCart(selectedPlant.id, 1); setSelectedPlant(null); }}
                  className="flex-grow py-4 bg-cta text-white rounded-xl font-bold hover:bg-cta/90 transition-all shadow-lg shadow-cta/20"
                >
                  Add to Cart
